import { setup, assign, fromCallback } from 'xstate';

type Tick = { symbol: string; price: number; ts: number };

export const dashboardMachine = setup({
  types: {
    context: {} as {
      last: Record<string, Tick>;
      count: number;
    },
    events: {} as
      | { type: 'PRICE_TICK'; tick: Tick }
      | { type: 'DISCONNECT' }
      | { type: 'RECONNECT' },
  },
  actors: {
    wsFeed: fromCallback<{ type: 'PRICE_TICK'; tick: Tick }>(({ sendBack }) => {
      const id = setInterval(() => {
        sendBack({
          type: 'PRICE_TICK',
          tick: { symbol: 'AAPL', price: 100 + Math.random(), ts: Date.now() },
        });
      }, 1000);
      return () => clearInterval(id);
    }),
  },
}).createMachine({
  id: 'dashboard',
  initial: 'connected',
  context: { last: {}, count: 0 },
  states: {
    connected: {
      invoke: { src: 'wsFeed', id: 'feed' },
      on: {
        PRICE_TICK: {
          actions: assign({
            last: ({ context, event }) => ({ ...context.last, [event.tick.symbol]: event.tick }),
            count: ({ context }) => context.count + 1,
          }),
        },
        DISCONNECT: { target: 'offline' },
      },
    },
    offline: {
      on: { RECONNECT: { target: 'connected' } },
    },
  },
});
