Schedule a delayed internal `REDRAW` via `raise` with an `id`, and `cancel` it every time a new `TICK` arrives; only the last scheduled one fires.

```typescript
import { setup, assign, raise, cancel } from 'xstate';

export const debouncedDash = setup({
  types: {
    context: {} as { buffer: number[]; last: number[] },
    events: {} as { type: 'TICK'; value: number } | { type: 'REDRAW' },
  },
}).createMachine({
  id: 'debounced',
  context: { buffer: [], last: [] },
  on: {
    TICK: {
      actions: [
        assign({ buffer: ({ context, event }) => [...context.buffer, event.value] }),
        cancel('redraw'),
        raise({ type: 'REDRAW' }, { id: 'redraw', delay: 200 }),
      ],
    },
    REDRAW: {
      actions: assign({
        last: ({ context }) => context.buffer,
        buffer: () => [],
      }),
    },
  },
});
