A `type: 'parallel'` state runs all its child regions simultaneously; each has its own `initial` and transitions. Events fan out to every region whose current state defines a handler, so a `TICK` can both feed data and trigger a render region independently.

```typescript
import { setup, assign } from 'xstate';

export const dashMachine = setup({
  types: {
    context: {} as { renders: number; latest: number | null },
    events: {} as
      | { type: 'WS_OPEN' }
      | { type: 'WS_CLOSE' }
      | { type: 'TICK'; value: number }
      | { type: 'RENDER_DONE' },
  },
}).createMachine({
  id: 'dash',
  type: 'parallel',
  context: { renders: 0, latest: null },
  states: {
    feed: {
      initial: 'closed',
      states: {
        closed: { on: { WS_OPEN: 'open' } },
        open: {
          on: {
            WS_CLOSE: 'closed',
            TICK: { actions: assign({ latest: ({ event }) => event.value }) },
          },
        },
      },
    },
    chart: {
      initial: 'idle',
      states: {
        idle: {
          on: { TICK: 'rendering' },
        },
        rendering: {
          on: {
            RENDER_DONE: {
              target: 'idle',
              actions: assign({ renders: ({ context }) => context.renders + 1 }),
            },
          },
        },
      },
    },
  },
});
