Guards live in `setup({ guards: { ... } })` and are referenced by string from transitions. Each receives `({ context, event })` and returns a boolean. Declaring them in setup gets the best type inference and makes them reusable across transitions.

```typescript
import { setup, assign } from 'xstate';

export const filterPanel = setup({
  types: {
    context: {} as { q: string; category: string | null; applied: boolean },
    events: {} as
      | { type: 'SET_Q'; value: string }
      | { type: 'SET_CATEGORY'; value: string | null }
      | { type: 'APPLY' },
  },
  guards: {
    hasInput: ({ context }) =>
      context.q.trim().length > 0 || context.category !== null,
  },
}).createMachine({
  id: 'panel',
  context: { q: '', category: null, applied: false },
  on: {
    SET_Q: { actions: assign({ q: ({ event }) => event.value }) },
    SET_CATEGORY: { actions: assign({ category: ({ event }) => event.value }) },
    APPLY: {
      guard: 'hasInput',
      actions: assign({ applied: () => true }),
    },
  },
});
