```typescript
import { setup, assign, enqueueActions, emit } from 'xstate';

type Facets = { status: string | null; owner: string | null; priority: number | null };

export const facetFilterMachine = setup({
  types: {
    context: {} as { facets: Facets; applied: Facets | null },
    events: {} as
      | { type: 'SET'; key: keyof Facets; value: string | number | null }
      | { type: 'APPLY' }
      | { type: 'RESET' },
    emitted: {} as { type: 'searchRequested'; facets: Facets },
  },
  guards: {
    hasAnyFacet: ({ context }) =>
      Object.values(context.facets).some((v) => v !== null),
  },
  actions: {
    setFacet: assign({
      facets: ({ context, event }) => {
        if (event.type !== 'SET') return context.facets;
        return { ...context.facets, [event.key]: event.value };
      },
    }),
    commitApplied: assign({ applied: ({ context }) => ({ ...context.facets }) }),
    clearFacets: assign({
      facets: () => ({ status: null, owner: null, priority: null }),
    }),
  },
}).createMachine({
  id: 'facet',
  initial: 'idle',
  context: {
    facets: { status: null, owner: null, priority: null },
    applied: null,
  },
  states: {
    idle: {
      on: {
        SET: { actions: 'setFacet' },
        APPLY: {
          actions: enqueueActions(({ context, enqueue, check }) => {
            if (check('hasAnyFacet')) {
              enqueue('commitApplied');
              enqueue(emit({ type: 'searchRequested', facets: context.facets }));
            }
          }),
        },
        RESET: { actions: 'clearFacets' },
      },
    },
  },
});
```

