```typescript
import { setup, assign, fromTransition, type ActorRefFrom } from 'xstate';

export const tabLogic = fromTransition(
  (
    state: { content: string; dirty: boolean },
    event: { type: 'EDIT'; value: string } | { type: 'SAVE' },
  ) => {
    if (event.type === 'EDIT') return { content: event.value, dirty: true };
    if (event.type === 'SAVE') return { ...state, dirty: false };
    return state;
  },
  { content: '', dirty: false },
);

type TabRef = ActorRefFrom<typeof tabLogic>;

export const editorMachine = setup({
  types: {
    context: {} as {
      tabs: { id: string; ref: TabRef }[];
      activeId: string | null;
    },
    events: {} as
      | { type: 'OPEN'; id: string }
      | { type: 'CLOSE'; id: string }
      | { type: 'ACTIVATE'; id: string },
  },
  actors: { tabLogic },
}).createMachine({
  id: 'editor',
  context: { tabs: [], activeId: null },
  on: {
    OPEN: {
      actions: assign({
        tabs: ({ context, event, spawn }) => [
          ...context.tabs,
          { id: event.id, ref: spawn('tabLogic', { id: event.id }) },
        ],
        activeId: ({ event }) => event.id,
      }),
    },
    CLOSE: {
      actions: assign({
        tabs: ({ context, event }) =>
          context.tabs.filter((t) => t.id !== event.id),
        activeId: ({ context, event }) =>
          context.activeId === event.id ? null : context.activeId,
      }),
    },
    ACTIVATE: {
      actions: assign({ activeId: ({ event }) => event.id }),
    },
  },
});
```

