          actions: assign({
            pending: ({ context, event }) => {
              const card = context.cards.find((c) => c.id === event.id);
              return card ? { id: event.id, from: card.column } : null;
            },
            cards: ({ context, event }) =>
              context.cards.map((c) => (c.id === event.id ? { ...c, column: event.column } : c)),
          }),
        },
