          target: 'idle',
          actions: assign({ pending: () => null }),
        },
        onError: {
          target: 'idle',
          actions: assign({
            cards: ({ context }) =>
              context.pending
                ? context.cards.map((c) =>
                    c.id === context.pending!.id ? { ...c, column: context.pending!.from } : c,
