  types: {
    context: {} as {
      nodes: Record<string, Node>;
      loading: Set<string>;
      expanded: Set<string>;
      error: string | null;
    },
    events: {} as
      | { type: 'EXPAND'; id: string }
      | { type: 'LOADED'; id: string; childIds: string[]; children: Node[] }
      | { type: 'FAILED'; id: string; error: string },
  },
  actors: {
    loadChildren: fromPromise<{ id: string; children: Node[] }, { id: string }>(
      async ({ input }) => {
        const r = await fetch(`/nodes/${input.id}/children`);
        const children: Node[] = await r.json();
        return { id: input.id, children };
      },
    ),
  },
}).createMachine({
  id: 'tree',
  context: { nodes: {}, loading: new Set(), expanded: new Set(), error: null },
  on: {
    EXPAND: {
      actions: assign({
        loading: ({ context, event }) => new Set(context.loading).add(event.id),
        expanded: ({ context, event }) => new Set(context.expanded).add(event.id),
      }),
    },
    LOADED: {
      actions: assign({
        nodes: ({ context, event }) => {
          const merged = { ...context.nodes };
          for (const c of event.children) merged[c.id] = c;
          if (merged[event.id]) merged[event.id] = { ...merged[event.id], childIds: event.childIds };
          return merged;
        },
        loading: ({ context, event }) => {
          const next = new Set(context.loading);
          next.delete(event.id);
          return next;
        },
      }),
    },
    FAILED: {
      actions: assign({
        loading: ({ context, event }) => {
          const next = new Set(context.loading);
          next.delete(event.id);
          return next;
        },
        error: ({ event }) => event.error,
      }),
    },
  },
});
