    events: {} as { type: 'SEND'; body: string },
  },
  actors: {
    post: fromPromise<{ id: string }, { body: string }>(async ({ input }) => {
      const r = await fetch('/c', { method: 'POST', body: JSON.stringify(input) });
      if (!r.ok) throw new Error('net');
      return r.json();
    }),
  },
}).createMachine({
  id: 'thread',
  initial: 'idle',
  context: { comments: [], pendingId: null },
  states: {
    idle: {
      on: {
        SEND: {
          target: 'posting',
          actions: assign({
            comments: ({ context, event }) => [
              ...context.comments,
              { id: 'tmp', body: event.body, state: 'pending' as const },
            ],
            pendingId: () => 'tmp',
          }),
        },
      },
    },
    posting: {
      invoke: {
        src: 'post',
        input: ({ context }) => ({
          body: context.comments.find((c) => c.id === context.pendingId)?.body ?? '',
        }),
        onDone: {
          target: 'idle',
