import { setup, assign, fromPromise } from 'xstate';

type Comment = { id: string; body: string; status: 'ok' | 'pending' | 'failed' };

export const commentsMachine = setup({
  types: {
    context: {} as { comments: Comment[]; workingId: string | null },
    events: {} as
      | { type: 'SEND'; body: string }
      | { type: 'RETRY'; id: string },
  },
  actors: {
    post: fromPromise<{ id: string }, { body: string }>(async ({ input }) => {
      const r = await fetch('/c', { method: 'POST', body: JSON.stringify(input) });
      if (!r.ok) throw new Error('fail');
      return r.json();
    }),
  },
  actions: {
    insertPending: assign({
      comments: ({ context, event }) => {
        if (event.type !== 'SEND') return context.comments;
        return [
          ...context.comments,
          { id: `tmp-${context.comments.length}`, body: event.body, status: 'pending' as const },
        ];
      },
      workingId: ({ context, event }) =>
        event.type === 'SEND' ? `tmp-${context.comments.length}` : context.workingId,
    }),
    markPendingForRetry: assign({
      comments: ({ context, event }) => {
        if (event.type !== 'RETRY') return context.comments;
        return context.comments.map((c) =>
          c.id === event.id ? { ...c, status: 'pending' as const } : c,
        );
      },
      workingId: ({ context, event }) =>
        event.type === 'RETRY' ? event.id : context.workingId,
    }),
    confirm: assign({
      comments: ({ context, event }) => {
        if (event.type !== 'xstate.done.actor.post' as never) return context.comments;
        const done = event as unknown as { output: { id: string } };
        return context.comments.map((c) =>
          c.id === context.workingId ? { ...c, id: done.output.id, status: 'ok' as const } : c,
        );
      },
      workingId: () => null,
    }),
    markFailed: assign({
      comments: ({ context }) =>
        context.comments.map((c) =>
          c.id === context.workingId ? { ...c, status: 'failed' as const } : c,
        ),
      workingId: () => null,
    }),
  },
}).createMachine({
  id: 'comments',
  initial: 'idle',
  context: { comments: [], workingId: null },
  states: {
    idle: {
      on: {
        SEND: { target: 'sending', actions: 'insertPending' },
        RETRY: { target: 'sending', actions: 'markPendingForRetry' },
      },
    },
    sending: {
      invoke: {
        src: 'post',
        input: ({ context }) => ({
          body:
            context.comments.find((c) => c.id === context.workingId)?.body ?? '',
        }),
        onDone: { target: 'idle', actions: 'confirm' },
        onError: { target: 'idle', actions: 'markFailed' },
      },
    },
  },
});
