The flow has two async steps. `requestPermission` resolves to `'granted' | 'denied' | 'default'`. On granted, a second `fromPromise` actor registers the push subscription. Both actors are declared in `setup.actors`, invoked from their own state, and their output flows into context via `onDone`. Strict typing via `setup.types` ensures every transition target is a declared state.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Perm = 'granted' | 'denied' | 'default';

export const notifFlow = setup({
  types: {
    context: {} as { perm: Perm; endpoint: string | null },
    events: {} as { type: 'START' },
  },
  actors: {
    ask: fromPromise<Perm, void>(async () => Notification.requestPermission()),
    subscribe: fromPromise<{ endpoint: string }, void>(async () => {
      const r = await fetch('/push/subscribe', { method: 'POST' });
      return r.json();
    }),
  },
  guards: {
    isGranted: ({ context }) => context.perm === 'granted',
  },
}).createMachine({
  id: 'notifFlow',
  initial: 'idle',
  context: { perm: 'default', endpoint: null },
  states: {
    idle: { on: { START: 'asking' } },
    asking: {
      invoke: {
        src: 'ask',
        onDone: {
          target: 'decide',
          actions: assign({ perm: ({ event }) => event.output }),
        },
      },
    },
    decide: {
      always: [
        { guard: 'isGranted', target: 'subscribing' },
        { target: 'denied' },
      ],
    },
    subscribing: {
      invoke: {
        src: 'subscribe',
        onDone: {
          target: 'subscribed',
          actions: assign({ endpoint: ({ event }) => event.output.endpoint }),
        },
        onError: { target: 'denied' },
      },
    },
    subscribed: { type: 'final' },
    denied: {},
  },
});
